def knapsack(items, capacity):
 n = len(items)
 dp = [[0 for _ in range(capacity+1)] for _ in range(n+1)]

 for i in range(1, n+1):
  for j in range(capacity+1):
   if items[i-1][1] <= j:
    dp[i][j] = max(items[i-1][0] + dp[i-1][j-items[i-1][1]], dp[i-1][j])
   else:
    dp[i][j] = dp[i-1][j]

 return dp[n][capacity]

