def find_primes(x, y):
    result = []
    for num in range(x, y + 1):
        if num > 1:
            isPrime = True
            for i in range(2, num//2 + 1):
                if num % i == 0:
                    isPrime = False
                    break
            if isPrime:
                result.append(num)
    return result

